def sum_div(n):
    if n == 1:
        return 0
    total = 1
    sqrt_n = int(n ** 0.5)
    for i in range(2, sqrt_n + 1):
        if n % i == 0:
            total += i
            if n // i != i:
                total += n // i
    return total

assert sum_div(8) == 7
assert sum_div(12) == 16
assert sum_div(7) == 1

